fun totalWeight(items: List<Item>): Double =
    items.sumOf { it.weight }   // weights like 0.1, 0.2

@Test
fun `total of ten 0_1 weights is 1`() {
    val items = List(10) { Item(weight = 0.1) }
    assertTrue(totalWeight(items) == 1.0)
}
